  ('optician-moex-01499', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '利用紅綠雙色檢查（douchrome test）視標確認患者矯正情形時，若患者主述紅色背景裡的數字比綠色背 景裡的數字較黑、較清楚，下列處置何者正確？', '["不論是近視或遠視均增加負度數", "不論是近視或遠視均增加正度數", "遠視往負度數增加、近視往正度數增加", "遠視往正度數增加、近視往負度數增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "0e99d0ca894b", "answer_pdf_sha1": "b01b4ba5666a", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
